3_real_world_example.code:
class User {
  constructor(name) {
    this.name = name;
  }

  // Standard Method (Goes on Prototype, saves memory)
  sayHello() {
    console.log(`Hi, I am ${this.name}`);
  }

  // Arrow Function Field (Goes on Instance, wastes memory but fixes 'this')
  boundHello = () => {
    console.log(`Hi, I am ${this.name}`);
  }
}

const u = new User('Alice');
u.sayHello();

